"    background: #ff6b6b;\n"
"    color: white;\n"
"}\n"
"\n"
"/* ========== SCROLL AREA ========== */\n"
"QScrollArea {\n"
"    border: 1px solid #e6ecf5;\n"
"    border-radius: 12px;\n"
"    background: white;\n"
"}\n"
"\n"
"/* ========== DATE EDIT ========== */\n"
"QDateEdit {\n"
"    background: white;\n"
"    color: #2c3e50;\n"
"    border: 1px solid #d8e1ec;\n"
"    border-radius: 10px;\n"
"    padding: 8px 12px;\n"
"    font-size: 13px;\n"
"}\n"
"\n"
"QDateEdit:hover {\n"
"    border: 1px solid #3498db;\n"
"}\n"
"\n"
"QDateEdit:focus {\n"
"    border: 1px solid #2980b9;\n"
"}\n"
"\n"
"/* ========== DIAL ========== */\n"
